import{_ as a,o as i,c as t,ag as o}from"./chunks/framework.BVZs_YW1.js";const g=JSON.parse('{"title":"自动登录环境下的 Keyring 冲突","description":"","frontmatter":{},"headers":[],"relativePath":"notes/desktop/keyring-conflict.md","filePath":"notes/desktop/keyring-conflict.md"}'),l={name:"notes/desktop/keyring-conflict.md"};function n(r,e,s,c,d,p){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="自动登录环境下的-keyring-冲突" tabindex="-1">自动登录环境下的 Keyring 冲突 <a class="header-anchor" href="#自动登录环境下的-keyring-冲突" aria-label="Permalink to &quot;自动登录环境下的 Keyring 冲突&quot;">​</a></h1><p>这个问题一般出现在下面这种组合里：</p><ul><li><code>greetd</code> 自动登录</li><li>KDE 和 niri 混着用</li><li>浏览器一启动就弹 Keyring / KWallet</li><li>换桌面环境以后，Cookie 或登录状态又没了</li></ul><h2 id="问题本质" tabindex="-1">问题本质 <a class="header-anchor" href="#问题本质" aria-label="Permalink to &quot;问题本质&quot;">​</a></h2><p>不是浏览器坏了，而是密码存储后端在不同桌面环境之间来回切。</p><ul><li>KDE 通常走 <code>kwallet</code></li><li>GNOME / niri 这边更常见的是 <code>gnome-keyring</code></li></ul><p>如果你是自动登录、单用户、物理环境也相对安全的机器，最省事的做法不是继续调它们的兼容性，而是直接让浏览器别依赖系统 Keyring。</p><h2 id="解决方法" tabindex="-1">解决方法 <a class="header-anchor" href="#解决方法" aria-label="Permalink to &quot;解决方法&quot;">​</a></h2><p>在 <code>~/.config/chrome-flags.conf</code> 追加：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>--password-store=basic</span></span></code></pre></div><p>这样浏览器会改用自己的基础存储方式，不再来回碰系统 Keyring。</p><h2 id="额外一步-去掉弹窗" tabindex="-1">额外一步：去掉弹窗 <a class="header-anchor" href="#额外一步-去掉弹窗" aria-label="Permalink to &quot;额外一步：去掉弹窗&quot;">​</a></h2><ul><li>KDE 用 <code>kwalletmanager</code></li><li>GNOME 体系用 <code>seahorse</code></li></ul><p>把原有密钥环密码清空，弹窗基本也就跟着消失了。</p>',14)])])}const u=a(l,[["render",n]]);export{g as __pageData,u as default};
